const Roster=()=>{const[f,sF]=useState("all");const[sel,sSel]=useState(null);const[q,sQ]=useState("");if(sel)return <Prof p={sel} back={()=>sSel(null)}/>;const ls=PL.filter(p=>(f==="all"||p.pos===f)&&p.nm.toLowerCase().includes(q.toLowerCase()));return(<div style={{padding:"0 0 110px",animation:"fu .3s ease"}}><Hero src={BD} h={140}><div style={{display:"flex",justifyContent:"space-between",alignItems:"flex-end",paddingTop:48,paddingBottom:16}}><div><h1 style={{fontFamily:fd,fontSize:28,fontWeight:800,color:"#fff",margin:0,textShadow:"0 2px 8px rgba(0,0,0,.5)"}}>Roster</h1><p style={{color:"rgba(255,255,255,.6)",fontSize:13,margin:"4px 0 0"}}>Varsity Squad · {PL.length} Players</p></div></div></Hero><div style={{padding:"16px 20px 0"}}><Cd sx={{display:"flex",alignItems:"center",gap:10,padding:"12px 16px",marginBottom:14,minHeight:48}}><I n="search" s={18} c={C.dim}/><input value={q} onChange={e=>sQ(e.target.value)} placeholder="Search by name..." style={{flex:1,background:"none",border:"none",color:C.ink,fontSize:15,fontFamily:ff,outline:"none"}}/>{q&&<button onClick={()=>sQ("")} style={{background:C.el,border:"none",borderRadius:8,width:28,height:28,display:"flex",alignItems:"center",justifyContent:"center",cursor:"pointer",fontSize:14,color:C.sub}}>×</button>}</Cd><div style={{display:"flex",gap:6,marginBottom:18,overflowX:"auto"}}>{["all","PG","SG","SF","PF","C"].map(pos=><button key={pos} onClick={()=>sF(pos)} style={{padding:"10px 18px",borderRadius:12,fontSize:13,fontWeight:f===pos?700:500,fontFamily:ff,background:f===pos?C.br:C.cd,color:f===pos?"#fff":C.sub,border:f===pos?"none":`1px solid ${C.ln}`,cursor:"pointer",whiteSpace:"nowrap",minHeight:44}}>{pos==="all"?"All Positions":pos}</button>)}</div>{ls.map(p=><Cd key={p.id} tap={()=>sSel(p)} sx={{display:"flex",alignItems:"center",gap:12,marginBottom:8,minHeight:72}}><div style={{position:"relative"}}><Av ch={p.av} sz={50} img={p.img}/>{p.st==="injured"&&<div style={{position:"absolute",bottom:-2,right:-2,width:16,height:16,borderRadius:"50%",background:C.ro,border:`2px solid ${C.cd}`,display:"flex",alignItems:"center",justifyContent:"center",fontSize:8,color:"#fff"}}>!</div>}</div><div style={{flex:1}}><div style={{fontSize:15,fontWeight:700,color:C.ink}}>{p.nm}</div><div style={{display:"flex",gap:6,marginTop:4,alignItems:"center"}}><Pill t={p.pos} c={C.br} b={C.brS}/><span style={{fontSize:12,color:C.sub}}>{p.ag}</span></div></div><div style={{textAlign:"right"}}><div style={{fontFamily:fd,fontSize:24,fontWeight:800,color:C.ink}}>{p.rt}</div><div style={{fontSize:12,color:p.tr[0]==="+"?C.gT:C.ro,fontWeight:700}}>{p.tr}</div></div><I n="right" s={16} c={C.dim}/></Cd>)}</div><button style={{position:"fixed",bottom:96,right:24,width:56,height:56,borderRadius:16,background:`linear-gradient(135deg,${C.br},${C.br2})`,border:"none",cursor:"pointer",display:"flex",alignItems:"center",justifyContent:"center",boxShadow:`0 8px 28px ${C.brG}`,zIndex:50}}><I n="plus" s={24} c="#fff"/></button></div>);};

