export default function App(){const[scr,setScr]=useState("ob");const[tab,setTab]=useState(0);useEffect(()=>{if(Capacitor.isNativePlatform()){StatusBar.setStyle({style:Style.Dark}).catch(()=>{});StatusBar.setBackgroundColor({color:"#0C0C10"}).catch(()=>{});}},[]);const tabs=[{l:"Home",i:"home"},{l:"Roster",i:"users"},{l:"Schedule",i:"cal"},{l:"Content",i:"book"},{l:"Chat",i:"chat"},{l:"More",i:"grid"}];const views=[<Home key="h" go={setTab}/>,<Roster key="r"/>,<SchedTab key="s"/>,<ContTab key="c"/>,<ChatTab key="ch"/>,<MoreTab key="m"/>];return(<><style>{`*{box-sizing:border-box;margin:0;padding:0;-webkit-font-smoothing:antialiased;}body{background:${C.bg};}@keyframes fu{from{opacity:0;transform:translateY(8px);}to{opacity:1;transform:translateY(0);}}input::placeholder{color:${C.dim};}::-webkit-scrollbar{display:none;}.tab-bar{padding:6px 4px max(28px,calc(env(safe-area-inset-bottom) + 6px)) !important;}`}</style><div style={{maxWidth:430,margin:"0 auto",minHeight:"100vh",background:C.bg,fontFamily:ff,position:"relative"}}>{scr==="ob"?<Onboard done={()=>setScr("app")}/>:<><div style={{overflowY:"auto",height:"100vh"}}>{views[tab]}</div><div style={{position:"fixed",bottom:0,left:"50%",transform:"translateX(-50%)",width:"100%",maxWidth:430,background:"rgba(12,12,16,.92)",backdropFilter:"blur(20px)",borderTop:`1px solid ${C.ln}`,display:"flex",padding:"6px 4px 28px",zIndex:100}} className="tab-bar">{tabs.map((t,i)=><button key={i} onClick={()=>setTab(i)} style={{flex:1,display:"flex",flexDirection:"column",alignItems:"center",gap:4,padding:"8px 0",background:"none",border:"none",cursor:"pointer",position:"relative",minHeight:48}}>{tab===i&&<div style={{position:"absolute",top:0,width:28,height:3,borderRadius:2,background:C.br}}/>}<I n={t.i} s={22} c={tab===i?C.br:C.dim}/><span style={{fontSize:10,color:tab===i?C.br:C.dim,fontWeight:tab===i?700:500,fontFamily:ff}}>{t.l}</span>{t.l==="Chat"&&<div style={{position:"absolute",top:4,right:"50%",marginRight:-15,width:8,height:8,borderRadius:"50%",background:C.br}}/>}</button>)}</div></>}</div></>);}
